const rows = $input.all().map(item => item.json);

const latestBySymbol = {};

for (const row of rows) {
  if (!row.Symbol) continue;
  latestBySymbol[row.Symbol] = row;
}

const cleanRows = Object.values(latestBySymbol).map(row => ({
  Symbol: row.Symbol,
  Company: row.Company,
  CurrentPrice: Number(row.CurrentPrice || row.Price || 0),
  ChangePercent: Number(row.ChangePercent || 0),
  Signal: row.Signal || row.signal || "WATCH",
  Volume: Number(row.Volume || 0),
}));

const chartObject = {
  type: "bar",
  data: {
    labels: cleanRows.map(r => r.Symbol),
    datasets: [{
      label: "Daily Change %",
      data: cleanRows.map(r => r.ChangePercent)
    }]
  }
};

return {
  json: {
    rows: cleanRows,
    symbols: cleanRows.map(r => r.Symbol).join(", "),
    totalStocks: cleanRows.length,
    chart: JSON.stringify(chartObject)
  }
};

const meta = $json.chart.result[0].meta;

const current = Number(meta.regularMarketPrice);
const previous = Number(meta.previousClose);

const change = current - previous;
const changePercent = ((change / previous) * 100).toFixed(2);

let sentiment = "Neutral";

if (changePercent > 0.5) {
  sentiment = "Bullish";
} else if (changePercent < -0.5) {
  sentiment = "Bearish";
}

return {
  json: {
    index: "NIFTY 50",
    currentPrice: current,
    previousClose: previous,
    change: Number(change.toFixed(2)),
    changePercent: Number(changePercent),
    sentiment
  }
};

const rows = $("Code in JavaScript").first().json.rows || [];

const totalStocks = rows.length;

const avgChange = totalStocks
  ? (
      rows.reduce((sum, r) => sum + Number(r.ChangePercent || 0), 0) /
      totalStocks
    ).toFixed(2)
  : "0.00";

const best = [...rows].sort(
  (a, b) => Number(b.ChangePercent || 0) - Number(a.ChangePercent || 0)
)[0];

const worst = [...rows].sort(
  (a, b) => Number(a.ChangePercent || 0) - Number(b.ChangePercent || 0)
)[0];

const portfolioText =
  $("Portfolio AI").first().json.content?.parts?.[0]?.text ||
  "Portfolio analysis unavailable.";

const marketText =
  $("Market AI").first().json.content?.parts?.[0]?.text ||
  "Market summary unavailable.";

const chartUrl = $("Code in JavaScript").first().json.chartUrl || "";

const tableRows = rows
  .map((r) => {
    const change = Number(r.ChangePercent || 0);
    const changeColor =
      change > 0 ? "#16a34a" : change < 0 ? "#dc2626" : "#6b7280";

    return `
      <tr>
        <td>${r.Company || r.Symbol}</td>
        <td><b>${r.Symbol}</b></td>
        <td>₹${Number(r.CurrentPrice || 0).toFixed(2)}</td>
        <td style="color:${changeColor};font-weight:bold;">${change.toFixed(
      2
    )}%</td>
        <td>${r.Signal || "WATCH"}</td>
      </tr>
    `;
  })
  .join("");

const html = `
<html>
<body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,sans-serif;color:#111827;">

<div style="max-width:980px;margin:30px auto;background:#ffffff;border-radius:18px;padding:32px;">

  <h1 style="text-align:center;font-size:34px;margin-bottom:30px;">
    📊 Daily Stock Intelligence Report
  </h1>

  <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:35px;">
    <div style="background:#f8fafc;border-radius:14px;padding:20px;text-align:center;">
      <h2 style="margin:0;font-size:28px;">${totalStocks}</h2>
      <p style="margin:8px 0 0;color:#555;">Tracked Companies</p>
    </div>

    <div style="background:#f8fafc;border-radius:14px;padding:20px;text-align:center;">
      <h2 style="margin:0;font-size:28px;">${avgChange}%</h2>
      <p style="margin:8px 0 0;color:#555;">Average Change</p>
    </div>

    <div style="background:#ecfdf5;border-radius:14px;padding:20px;text-align:center;">
      <h2 style="margin:0;font-size:22px;color:#16a34a;">${
        best?.Symbol || "-"
      }</h2>
      <p style="margin:8px 0 0;color:#555;">Best Performer</p>
    </div>

    <div style="background:#fef2f2;border-radius:14px;padding:20px;text-align:center;">
      <h2 style="margin:0;font-size:22px;color:#dc2626;">${
        worst?.Symbol || "-"
      }</h2>
      <p style="margin:8px 0 0;color:#555;">Weakest Performer</p>
    </div>
  </div>

  ${
    chartUrl
      ? `
  <h2>📈 Daily Change Chart</h2>
  <div style="background:#f9fafb;border-radius:14px;padding:18px;margin-bottom:30px;text-align:center;">
    <img src="${chartUrl}" style="max-width:100%;border-radius:10px;" />
  </div>
  `
      : ""
  }

  <h2>🤖 Portfolio Analysis</h2>
  <div style="background:#f9fafb;border-radius:14px;padding:20px;line-height:1.7;margin-bottom:30px;">
    ${portfolioText.replace(/\n/g, "<br>")}
  </div>

  <h2>🌍 Overall Market Summary</h2>
  <div style="background:#f9fafb;border-radius:14px;padding:20px;line-height:1.7;margin-bottom:30px;">
    ${marketText.replace(/\n/g, "<br>")}
  </div>

  <h2>📋 Company Performance</h2>
  <table style="width:100%;border-collapse:collapse;margin-top:12px;">
    <tr style="background:#2563eb;color:white;">
      <th style="padding:12px;text-align:left;">Company</th>
      <th style="padding:12px;text-align:left;">Symbol</th>
      <th style="padding:12px;text-align:left;">Price</th>
      <th style="padding:12px;text-align:left;">Change %</th>
      <th style="padding:12px;text-align:left;">Signal</th>
    </tr>
    ${tableRows}
  </table>

  <p style="text-align:center;color:#6b7280;font-size:13px;margin-top:35px;">
    Generated automatically using n8n • Yahoo Finance • Gemini AI
  </p>

</div>
</body>
</html>
`;

return {
  json: {
    subject: `📊 Daily Stock Intelligence Report - ${new Date().toLocaleDateString(
      "en-IN"
    )}`,
    html,
  },
};
